import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useInView } from "react-intersection-observer";

const GallerySection = ({ images }) => {
  const [selectedImg, setSelectedImg] = useState(null);
  const { ref, inView } = useInView({ threshold: 0.1, triggerOnce: true });

  // Placeholder gradient images if no real images provided
  const galleryImages = images.length > 0 ? images : [
    { src: null, alt: "Couple Photo 1", gradient: "from-red-900 to-red-700" },
    { src: null, alt: "Couple Photo 2", gradient: "from-yellow-900 to-yellow-700" },
    { src: null, alt: "Couple Photo 3", gradient: "from-red-800 to-yellow-800" },
    { src: null, alt: "Couple Photo 4", gradient: "from-yellow-800 to-red-900" },
    { src: null, alt: "Couple Photo 5", gradient: "from-red-900 to-yellow-900" },
    { src: null, alt: "Couple Photo 6", gradient: "from-yellow-900 to-red-800" },
  ];

  return (
    <section
      ref={ref}
      className="relative py-24 px-4 overflow-hidden"
      style={{ background: "linear-gradient(180deg, #1a0a0a 0%, #2d0a0a 50%, #1a0a0a 100%)" }}
    >
      <motion.div
        initial={{ opacity: 0, y: 40 }}
        animate={inView ? { opacity: 1, y: 0 } : {}}
        transition={{ duration: 1 }}
        className="text-center mb-16"
      >
        <span className="ornament">✦ ✦ ✦</span>
        <h2 className="font-serif text-4xl md:text-5xl gold-text mt-4 mb-2">Our Gallery</h2>
        <p className="font-sans text-beige/50 tracking-widest text-sm uppercase">
          Moments we cherish
        </p>
      </motion.div>

      <div className="max-w-5xl mx-auto grid grid-cols-2 md:grid-cols-3 gap-4">
        {galleryImages.map((img, i) => (
          <motion.div
            key={i}
            initial={{ opacity: 0, scale: 0.8 }}
            animate={inView ? { opacity: 1, scale: 1 } : {}}
            transition={{ duration: 0.6, delay: i * 0.1, ease: [0.23, 1, 0.32, 1] }}
            whileHover={{ scale: 1.05, zIndex: 10 }}
            className="relative overflow-hidden rounded-lg cursor-pointer group"
            style={{ aspectRatio: i === 0 || i === 5 ? "1/1.3" : "1/1" }}
            onClick={() => setSelectedImg(img)}
          >
            {img.src ? (
              <img
                src={img.src}
                alt={img.alt}
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
              />
            ) : (
              <div
                className={`w-full h-full bg-gradient-to-br ${img.gradient} flex items-center justify-center`}
              >
                <span className="text-gold/40 text-5xl">💍</span>
              </div>
            )}
            {/* Hover overlay */}
            <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-end p-4">
              <p className="text-gold text-sm font-serif">{img.alt}</p>
            </div>
            {/* Gold border on hover */}
            <div className="absolute inset-0 border-2 border-gold/0 group-hover:border-gold/50 rounded-lg transition-all duration-300" />
          </motion.div>
        ))}
      </div>

      {/* Lightbox */}
      <AnimatePresence>
        {selectedImg && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4"
            onClick={() => setSelectedImg(null)}
          >
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.8, opacity: 0 }}
              transition={{ duration: 0.4, ease: [0.23, 1, 0.32, 1] }}
              className="relative max-w-2xl w-full"
              onClick={(e) => e.stopPropagation()}
            >
              {selectedImg.src ? (
                <img src={selectedImg.src} alt={selectedImg.alt} className="w-full rounded-lg" />
              ) : (
                <div
                  className={`w-full h-96 bg-gradient-to-br ${selectedImg.gradient} rounded-lg flex items-center justify-center`}
                >
                  <span className="text-gold/40 text-8xl">💍</span>
                </div>
              )}
              <button
                onClick={() => setSelectedImg(null)}
                className="absolute -top-4 -right-4 w-10 h-10 rounded-full bg-gold text-dark-bg font-bold text-lg flex items-center justify-center hover:scale-110 transition-transform"
              >
                ×
              </button>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </section>
  );
};

export default GallerySection;
